\section{Internal Lean helper lemmas}
\label{sec:thm32_lean_helpers}

The Lean proof of \cref{thm:rational_map_to_av_extends} factors through a small
chain of internal helper lemmas that decompose the two-input combination above
into self-contained, separately-checkable pieces. These carry no external
mathematical source; each is a packaging step internal to the formalisation.

\begin{lemma}[A scheme smooth over a field is reduced]
  \label{lem:isReduced_of_smooth_over_field}
  \lean{AlgebraicGeometry.Scheme.RationalMap.isReduced_of_smooth_over_field}
  For an object \(A\) over \(\Spec \bar k\) whose structure morphism
  \(A.\mathrm{hom}\) is smooth, the underlying scheme \(A.\mathrm{left}\) is
  reduced.
  \begin{proof}
    Proved directly in Lean.
  \end{proof}
\end{lemma}

\begin{lemma}[Integrality of the abelian variety]
  \label{lem:av_isIntegral_of_smooth_geomIrred}
  \lean{AlgebraicGeometry.Scheme.RationalMap.av_isIntegral_of_smooth_geomIrred}
  \uses{lem:isReduced_of_smooth_over_field}
  For an abelian variety \(A\) over an algebraically closed field \(\bar k\)
  (encoded as \(A\) over \(\Spec \bar k\) with group-object, proper, smooth, and
  geometrically irreducible structure), the underlying scheme \(A.\mathrm{left}\)
  is integral: it is irreducible (geometric irreducibility over the singleton
  base \(\Spec \bar k\)) and reduced
  (\cref{lem:isReduced_of_smooth_over_field}).
  \begin{proof}
    Proved directly in Lean.
  \end{proof}
\end{lemma}

\begin{lemma}[Empty indeterminacy locus gives codim-1-freeness]
  \label{lem:codimOneFree_of_indeterminacyLocus_eq_empty}
  \lean{AlgebraicGeometry.Scheme.RationalMap.codimOneFree_of_indeterminacyLocus_eq_empty}
  For a rational map \(f \colon X \dashrightarrow Y\) of schemes whose
  indeterminacy locus is empty, every codimension-\(1\) point of \(X\) lies in
  the domain of \(f\); that is, \(f\) is \(\mathrm{CodimOneFree}\).
  \begin{proof}
    Proved directly in Lean.
  \end{proof}
\end{lemma}

\begin{lemma}[Codim-1-freeness of a rational map into an abelian variety]
  \label{lem:av_codimOneFree_of_indeterminacy}
  \lean{AlgebraicGeometry.Scheme.RationalMap.av_codimOneFree_of_indeterminacy}
  \uses{lem:av_isIntegral_of_smooth_geomIrred, lem:codimOneFree_of_indeterminacyLocus_eq_empty, lem:milne_codim1_indeterminacy}
  For a rational map \(f \colon X \dashrightarrow A\) from a nonsingular variety
  \(X\) to an abelian variety \(A\) over an algebraically closed field \(\bar k\),
  the map \(f\) is \(\mathrm{CodimOneFree}\): every codimension-\(1\) point of
  \(X\) lies in \(f.\mathrm{domain}\). The pure-codim-\(1\)-or-empty dichotomy of
  Milne's Lemma~3.3 (\cref{lem:milne_codim1_indeterminacy}, applied with
  \(A.\mathrm{left}\) integral by
  \cref{lem:av_isIntegral_of_smooth_geomIrred}) is combined with the codim-\(\geq
  2\) conclusion to force the indeterminacy locus empty, whence the empty-locus
  branch (\cref{lem:codimOneFree_of_indeterminacyLocus_eq_empty}) concludes.
  \begin{proof}
    Proved directly in Lean.
  \end{proof}
\end{lemma}

\begin{lemma}[The two missing inputs for the extension theorem]
  \label{lem:av_isIntegral_and_codimOneFree}
  \lean{AlgebraicGeometry.Scheme.RationalMap.av_isIntegral_and_codimOneFree}
  \uses{lem:av_isIntegral_of_smooth_geomIrred, lem:av_codimOneFree_of_indeterminacy}
  For a rational map \(f \colon X \dashrightarrow A\) from a nonsingular variety
  to an abelian variety over an algebraically closed field \(\bar k\), the
  conjunction holds: \(A.\mathrm{left}\) is integral
  (\cref{lem:av_isIntegral_of_smooth_geomIrred}) and \(f\) is
  \(\mathrm{CodimOneFree}\) (\cref{lem:av_codimOneFree_of_indeterminacy}). This
  packages the two facts that \cref{thm:rational_map_to_av_extends} consumes in a
  single \(\mathrm{obtain}\).
  \begin{proof}
    Proved directly in Lean.
  \end{proof}
\end{lemma}

